import json, os
from pathlib import Path
ROBOT_PATH = {{primary_robot.path}}
PPO_CHECKPOINT = {{policy_checkpoint.checkpoint_path}}
CHECKPOINT_DIR = {{policy_checkpoint.checkpoint_dir}}
CALIBRATION_PATH = {{ood_detector.calibration_path}}
BASE_MODEL_ID = {{ood_detector.base_model}}
RUN_ID = {{policy_checkpoint.run_id}}
RESULT_FILE = "/tmp/ood_rollout_result.json"
NUM_STEPS = {{ood_detector.num_steps}}
CONSECUTIVE_THRESHOLD = {{ood_detector.consecutive_threshold}}
ACTION_BUFFER_LEN = {{ood_detector.action_buffer_len}}
ACTION_DIM = {{policy_checkpoint.action_dim}}
os.makedirs("/tmp", exist_ok=True)
Path(CHECKPOINT_DIR).mkdir(parents=True, exist_ok=True)
load_rl_policy(robot_path=ROBOT_PATH, policy_path=PPO_CHECKPOINT, action_dim=ACTION_DIM)
training_status = get_training_status(run_id=RUN_ID)
def _synth_action(step):
    base = [0.00, 0.20, -0.10, 1.50, 0.00, -1.20, 0.80]
    drift = 0.01 * step
    shift = 0.5 if step >= 30 else 0.0
    return [b + drift + (shift if i == 0 else 0.0) for i, b in enumerate(base)]
ACTION_BUFFER = []
per_step_ood = []
first_detection_step = None
consecutive_ood = 0
for step in range(NUM_STEPS):
    try:
        get_env_observations(env_id=0, run_id=RUN_ID)
    except Exception:
        pass
    action = _synth_action(step)
    ACTION_BUFFER.append(action)
    if len(ACTION_BUFFER) > ACTION_BUFFER_LEN:
        ACTION_BUFFER.pop(0)
    if len(ACTION_BUFFER) >= 2:
        tier1 = detect_ood(tier=1, action_sequence=ACTION_BUFFER)
    else:
        tier1 = {"is_ood": False}
    is_ood = bool(tier1.get("is_ood", False)) if isinstance(tier1, dict) and "error" not in tier1 else False
    per_step_ood.append({"step": step, "is_ood": is_ood})
    if is_ood:
        consecutive_ood += 1
        if consecutive_ood >= CONSECUTIVE_THRESHOLD and first_detection_step is None:
            first_detection_step = step
    else:
        consecutive_ood = 0
tier3 = None
if first_detection_step is not None:
    try:
        tier3 = detect_ood(tier=3, checkpoint_path=PPO_CHECKPOINT, calibration_path=CALIBRATION_PATH)
    except Exception as exc:
        tier3 = {"error": str(exc)}
try:
    reward_eval = evaluate_reward(reward_code="def compute_reward(obs, action, info): return 0.0", env_id="Isaac-FrankaPickPlace-v0", num_steps=10)
except Exception as exc:
    reward_eval = {"error": str(exc)}
forgetting_result = monitor_forgetting(checkpoint_dir=CHECKPOINT_DIR, base_model=BASE_MODEL_ID)
result = {"per_step_ood": per_step_ood, "first_detection_step": first_detection_step, "consecutive_threshold": CONSECUTIVE_THRESHOLD, "num_steps": NUM_STEPS, "tier3_confirmation": tier3, "training_status": training_status or {}, "reward_eval": reward_eval or {}, "forgetting": forgetting_result or {}, "rollout_complete": True}
with open(RESULT_FILE, "w") as f:
    json.dump(result, f, indent=2)
assert isinstance(per_step_ood, list) and len(per_step_ood) >= NUM_STEPS, "per_step_ood missing or short"
assert all("is_ood" in r for r in per_step_ood), "per_step_ood entries missing is_ood"
assert first_detection_step is None or isinstance(first_detection_step, int), "first_detection_step bad type"
assert os.path.exists(RESULT_FILE), "result file missing"
